mapper.insert:
INSERT INTO playlist_like (
  playlist_likeno, playlistno, memberno
) VALUES (
  playlist_like_seq.NEXTVAL, #{playlistno}, #{memberno}
)

mapper.delete:
DELETE FROM playlist_like
WHERE playlistno = #{playlistno}
  AND memberno = #{memberno}

mapper.select:
SELECT COUNT(*) FROM playlist_like
WHERE playlistno = #{playlistno}
  AND memberno = #{memberno}
